function createOverflowWrapper({document:document,element:element,isPointerDevice:isPointerDevice,inheritedClasses:inheritedClasses}){if(!element||!element.parentNode){console.error("[Overflow] Element or element.parentNode is null or undefined.");return null}try{const fragment=document.createDocumentFragment();const wrapper=document.createElement("div");wrapper.className="overflow-wrapper";fragment.appendChild(wrapper);if(inheritedClasses){inheritedClasses.forEach(cls=>{if(element.classList.contains(cls)){wrapper.classList.add(cls);element.classList.remove(cls)}})}let nav=null;if(isPointerDevice){const createButton=type=>{const button=document.createElement("button");button.type="button";button.className=`overflow-navButton overflow-navButton-${type} ui-icon mw-ui-icon-wikimedia-collapse`;button.setAttribute("aria-label",`Scroll ${type}`);button.setAttribute("title",`Scroll ${type}`);return button};nav=document.createElement("div");nav.className="overflow-nav";nav.appendChild(createButton("left"));nav.appendChild(createButton("right"));wrapper.appendChild(nav)}const content=document.createElement("div");content.className="overflow-content";wrapper.appendChild(content);const parentNode=element.parentNode;parentNode.insertBefore(fragment,element);content.appendChild(element);return{wrapper:wrapper,content:content,nav:nav}}catch(error){console.error(`[Overflow] Error occurred while wrapping element: ${error.message}`);return null}}